from flask import Flask, request, jsonify
from flask_login import current_user, login_required
from models import User, db

app = Flask(__name__)

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
def update_user(user_id):
    if not current_user.is_admin:
        return jsonify({"error": "Unauthorized"}), 403

    user = User.query.filter_by(id=user_id, tenant_id=current_user.tenant_id).first()
    if not user:
        return jsonify({"error": "User not found"}), 404

    data = request.json
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    admin_only_fields = ['role', 'account_status']

    for field in allowed_fields:
        if field in data:
            if field in admin_only_fields and not current_user.is_admin:
                return jsonify({"error": "Unauthorized to modify this field"}), 403
            setattr(user, field, data[field])

    db.session.commit()
    return jsonify({"message": "User updated successfully"}), 200

